module top_module(
    output Y,
    input A1,
    input A2,
    input A3,
    input A4,
    input EN
);wire [3:0] X_inputs;
    wire and_output;

    // Assign the X_inputs to a vector
    assign X_inputs = {A4, A3, A2, A1};

    // Perform AND operation on X_inputs and include enable
    assign and_output = (EN) ? (X_inputs[3] & X_inputs[2] & X_inputs[1] & X_inputs[0]) : 1'b0;

    // Assign the result to Y
    assign Y = and_output;

endmodule
